8â†’  const [username, setUsername] = useState('');
9â†’  const [password, setPassword] = useState('');
10â†’  const [error, setError] = useState('');
11â†’  const [loading, setLoading] = useState(false);
12â†’
13â†’  const handleSubmit = async (e) => {
14â†’    e.preventDefault();
15â†’    setLoading(true);
16â†’    setError('');
17â†’    try {
18â†’      const response = await axios.post(`${API}/token`,
19â†’        new URLSearchParams({ username, password }),
20â†’        { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } }
21â†’      );
22â†’      const token = response.data.access_token;
23â†’      localStorage.setItem('token', token);
24â†’      
25â†’      const userResponse = await axios.get(`${API}/users/me`, {
26â†’        headers: { Authorization: `Bearer ${token}` }
27â†’      });
28â†’      onLogin(userResponse.data);
29â†’    } catch (err) {
30â†’      setError('Login yoki parol xato');
31â†’      setLoading(false);
32â†’    }
33â†’  };
34â†’
35â†’  return (
36â†’    <div className="login-page">
37â†’      <form onSubmit={handleSubmit} className="login-card">
