41â†’          </div>
42â†’          <h2 className="login-title">SMART ESP32</h2>
43â†’          <p className="login-subtitle">Industrial Monitoring Portal</p>
44â†’        </div>
45â†’
46â†’        {error && <div className="login-error">{error}</div>}
47â†’
48â†’        <div className="login-field">
49â†’          <label>Foydalanuvchi</label>
50â†’          <input 
51â†’            type="text" 
52â†’            placeholder="Login kiriting"
53â†’            value={username} 
54â†’            onChange={(e) => setUsername(e.target.value)} 
55â†’            required 
56â†’            autoFocus
57â†’          />
58â†’        </div>
59â†’
60â†’        <div className="login-field">
61â†’          <label>Parol</label>
62â†’          <input 
63â†’            type="password" 
64â†’            placeholder="Parol kiriting"
65â†’            value={password} 
66â†’            onChange={(e) => setPassword(e.target.value)} 
67â†’            required 
68â†’          />
69â†’        </div>
70â†’
71â†’        <button type="submit" className="btn-submit login-btn" disabled={loading}>
72â†’          {loading ? 'Kutilmoqda...' : 'Kirish'}
73â†’        </button>
74â†’      </form>
75â†’    </div>
76â†’  );
77â†’};
78â†’
79â†’export default Login;
